arguments.argument:
if bWave=0
{
  waveTime+=1
  if waveTime>=210
  {
    bWave=1
    ballX=x; ballY=y
    ballTime=image_xscale*4
    waveTime=irandom(120)
  }
}

lightFlash+=1
if lightFlash=60
{
  image_blend=c_yellow
}
else if lightFlash>=63
{
  image_blend=c_white
  lightFlash=irandom(30)
}
